mapper.select:
select ifnull(sum(recharge_amount), 0.0000) as rechargeAmount
     , ifnull(sum(recharge_num), 0)         as rechargeNum
from `t_count_order`
where day_str >= #{startTime}
  and day_str <= #{endTime}
  and currency_id = #{currencyId}

select max(day_str) as dayStr , ifnull(sum(recharge_amount), 0.0000) as rechargeAmount , ifnull(sum(recharge_num), 0) as rechargeNum , ifnull(sum(withdraw_amount), 0.0000) as withdrawAmount , ifnull(sum(withdraw_num), 0) as withdrawNum , ifnull(sum(fee), 0) as fee , ifnull(sum(user_num), 0) as userNum , ifnull(sum(first_num), 0) as firstNum , ifnull(sum(first_amount), 0.0000) as firstAmount , ifnull(sum(real_amount), 0.0000) as realAmount , ifnull(sum(second_num), 0) as secondNum , ifnull(sum(second_amount), 0.0000) as secondAmount , ifnull(sum(three_remain_num), 0) as threeRemainNum , ifnull(sum(three_remain), 0.0000) as threeRemain , ifnull(sum(seven_remain_num), 0) as sevenRemainNum , ifnull(sum(seven_remain), 0.0000) as sevenRemain , ifnull(sum(bet_amount), 0.0000) as betAmount , ifnull(sum(bet_num), 0) as betNum , ifnull(sum(settle_amount), 0.0000) as settleAmount , ifnull(sum(win_lose_amount), 0.0000) as winLoseAmount , ifnull(sum(efficient_bet_amount), 0.0000) as efficientBetAmount , ifnull(sum(wait_rebate_amount), 0.0000) as waitRebateAmount , ifnull(sum(already_rebate_amount), 0.0000) as alreadyRebateAmount , ifnull(sum(wait_return_commission_amount), 0.0000) as waitReturnCommissionAmount , ifnull(sum(already_return_commission_amount), 0.0000) as alreadyReturnCommissionAmount , ifnull(sum(unclaimed_agent_salary_amount), 0.0000) as unclaimedAgentSalaryAmount , ifnull(sum(claimed_agent_salary_amount), 0.0000) as claimedAgentSalaryAmount , ifnull(sum(play_wheel_term_award), 0.0000) as playWheelTermAward , ifnull(sum(play_wheel_term_num), 0) as playWheelTermNum , ifnull(sum(bonus_amount), 0) as bonusAmount , ifnull(sum(customer_recharge_amount), 0) as customerRechargeAmount , ifnull(sum(customer_bonus_amount), 0) as customerBonusAmount , ifnull(sum(transfer_bonus_amount), 0) as transferBonusAmount , ifnull(sum(customer_recharge_num), 0) as customerRechargeNum , ifnull(sum(customer_real_cash_withdrawal_amount), 0) as customerRealCashWithdrawalAmount , ifnull(sum(customer_real_cash_withdrawal_num), 0) as customerRealCashWithdrawalNum , ifnull(sum(customer_real_cash_withdrawal_real_amount), 0) as customerRealCashWithdrawalRealAmount , ifnull(sum(customer_points_deducted_amount), 0) as customerPointsDeductedAmount , ifnull(sum(customer_points_deducted_num), 0) as customerPointsDeductedNum , ifnull(sum(activity_award_bonus_amount), 0) as activityAwardBonusAmount , ifnull(sum(receive_bonus_num), 0) as receiveBonusNum , ifnull(sum(activity_award_total_num), 0) as activityAwardTotalNum , ifnull(sum(receive_turntable_num), 0) as receiveTurntableNum , ifnull(sum(user_earnings), 0) as userEarnings , ifnull(sum(user_expenses), 0) as userExpenses , ifnull(sum(customer_loss_amount), 0) as customerLossAmount
, ifnull(sum(recharge_people_num), 0) as rechargePeopleNum , ifnull(sum(withdrawal_people_num), 0) as withdrawalPeopleNum , ifnull(sum(active_people_num), 0) as activePeopleNum , ifnull(sum(mpay_recharge_amount), 0) as mpayRechargeAmount , ifnull(sum(mpay_recharge_num), 0) as mpayRechargeNum , ifnull(sum(blockchain_recharge_amount), 0) as blockchainRechargeAmount , ifnull(sum(blockchain_recharge_num), 0) as blockchainRechargeNum , ifnull(sum(pixpay_recharge_amount), 0) as pixpayRechargeAmount , ifnull(sum(pixpay_recharge_num), 0) as pixpayRechargeNum , ifnull(sum(law_withdraw_amount), 0) as lawWithdrawAmount , ifnull(sum(law_withdraw_num), 0) as lawWithdrawNum , MAX(calculations_time) as calculationsTime , ifnull(sum(code_amount), 0) as codeAmount , ifnull(sum(pix_bonus_amount), 0) as pixBonusAmount , ifnull(sum(restore_amount), 0) as restoreAmount , ifnull(sum(restore_num), 0) as restoreNum , ifnull(sum(yndpay_recharge_amount), 0) as yndpayRechargeAmount , ifnull(sum(yndpay_recharge_num), 0) as yndpayRechargeNum , ifnull(sum(ynd_bonus_amount), 0) as yndBonusAmount , ifnull(sum(upay_bonus_amount), 0) as upayBonusAmount , ifnull(sum(upay_recharge_amount), 0) as upayRechargeAmount , ifnull(sum(upay_recharge_num), 0) as upayRechargeNum , ifnull(sum(pay1818_recharge_amount), 0) as pay1818RechargeAmount , ifnull(sum(pay1818_bonus_amount), 0) as pay1818BonusAmount , ifnull(sum(pay1818_recharge_num), 0) as pay1818RechargeNum , ifnull(sum(rupee_recharge_amount), 0) as rupeeRechargeAmount , ifnull(sum(rupee_recharge_num), 0) as rupeeRechargeNum , ifnull(sum(rupee_bonus_amount), 0) as rupeeBonusAmount , ifnull(sum(zloty_recharge_amount), 0) as zlotyRechargeAmount , ifnull(sum(zloty_recharge_num), 0) as zlotyRechargeNum , ifnull(sum(zloty_bonus_amount), 0) as zlotyBonusAmount , ifnull(sum(hwpay_recharge_amount), 0) as hwpayRechargeAmount , ifnull(sum(hwpay_recharge_num), 0) as hwpayRechargeNum , ifnull(sum(hwpay_bonus_amount), 0) as hwpayBonusAmount , ifnull(sum(u_recharge_amount), 0) as uRechargeAmount , ifnull(sum(u_recharge_num), 0) as uRechargeNum , ifnull(sum(u_bonus_amount), 0) as uBonusAmount , ifnull(sum(new_person_num), 0) as newPersonNum , ifnull(sum(new_person_amount), 0) as newPersonAmount , ifnull(sum(private_person_num), 0) as privatePersonNum , ifnull(sum(private_person_amount), 0) as privatePersonAmount , ifnull(sum(group_num), 0) as groupNum , ifnull(sum(group_amount), 0) as groupAmount , ifnull(sum(super_num), 0) as superNum , ifnull(sum(super_amount), 0) as superAmount , ifnull(sum(red_private_num), 0) as redPrivateNum , ifnull(sum(red_private_amount), 0) as redPrivateAmount , ifnull(sum(red_num), 0) as redNum , ifnull(sum(red_amount), 0) as redAmount , ifnull(sum(vip_reward_num), 0) as vipRewardNum , ifnull(sum(vip_reward_amount), 0) as vipRewardAmount , ifnull(sum(total_packet_amount), 0) as totalPacketAmount
from `t_count_order` where currency_id=#{currencyId}
and day_str >= #{startTime} and day_str <= #{endTime}

select *
from t_count_order
where day_str between #{startTime} and #{endTime}
  and currency_id = #{currencyId}
  and day_str <= #{monthEndTime}
order by day_str desc
limit 1
